namespace sv_1f9e03825e0547c594afb44a25e9bce7.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_1f9e03825e0547c594afb44a25e9bce7.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row gap-4">
    @* ── Left sidebar (filters) ── *@
    <div style="flex: 0 0 25%; max-width: 25%;">
        <div class="card">
            <div class="card-header fw-semibold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading categories…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small" for="minPrice">Min Price</label>
                    <input id="minPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label small" for="maxPrice">Max Price</label>
                    <input id="maxPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="maxPrice" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <div class="d-grid gap-2">
                    <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
                </div>
            </div>
        </div>
    </div>

    @* ── Main content area ── *@
    <div style="flex: 1 1 75%;">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
                <span class="ms-3">Loading products…</span>
            </div>
        }
        else if (result is not null && result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products match your criteria. Try adjusting the filters.
            </div>
        }
        else if (result is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-2" for="sortBy">Sort by</label>
                    <select id="sortBy" class="form-select form-select-sm d-inline-block w-auto"
                            @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @((result.Page - 1) * result.PageSize + 1)–@(Math.Min(result.Page * result.PageSize, result.TotalCount))
                    of @result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            <nav aria-label="Product pagination">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage - 1)" disabled="@(currentPage == 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= totalPages; i++)
                    {
                        var page = i;
                        <li class="page-item @(page == currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                        </li>
                    }
                    <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage + 1)" disabled="@(currentPage == totalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </div>
</div>

@code {
    // Filter state
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // Search state
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? result;
    private int totalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    // UI state
    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAndProducts();
    }

    private async Task LoadCategoriesAndProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = PerformSearch();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task PerformSearch()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );
            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await PerformSearch();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        sortBy = "price_asc";
        await PerformSearch();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await PerformSearch();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await PerformSearch();
    }

    private void HandleProductSelected(Product product)
    {
        // Parent-level handler — navigate to detail page
        // In a real app: NavigationManager.NavigateTo($"/catalog/{product.Id}");
    }

    private void HandleAddToCart(Product product)
    {
        // Add-to-cart handling
    }
}

@using sv_1f9e03825e0547c594afb44a25e9bce7.Services

<div class="card h-100 product-card" role="button" @onclick="OnCardClicked" style="cursor: pointer;">
    @* Placeholder image *@
    <div class="bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;" role="img" aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>

    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@($"{Product.Rating:F1} out of 5")">@GetStarRating(Product.Rating)</p>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2 align-self-start">Out of Stock</span>
        }

        <div class="mt-auto">
            <button class="btn btn-sm btn-success w-100"
                    disabled="@(!Product.InStock)"
                    @onclick="OnAddToCartClicked"
                    @onclick:stopPropagation="true">
                Add to Cart
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private static string GetStarRating(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

